var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"한 해의 끝을 장식하는 성스러운 밤.","JPN":"一年の終わりを飾る聖なる夜。","ENG":"The holy night comes at the end of every year.","TWN":"點綴一年之末的神聖之夜。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"이 밤에는 누구나 따뜻한 모닥불의 온기 속에서 일 년간의 즐거운 추억들을 떠올리곤 하지.","JPN":"この夜は誰もが暖かな暖炉を囲い、一年間の楽しい思い出を語り合う。","ENG":"During this night, people all over the hearth gather, sharing memories of the good moments from the year.","TWN":"在這個夜晚，每個人都會在溫暖的篝火前，回想過去一年中快樂的回憶。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만...... 세상 모든 일이 그렇듯이 예외는 있는 법이라네.","JPN":"しかし……例外が存在するのも世の常。","ENG":"But... just like everything else in the world, there's an exception.","TWN":"但是……總會有那麼一兩個意外，世事便是如此。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"예를 들어...... 해마다 어떤 산장에 나타난다고 알려진 <color=#ffd34c>성야의 살인마</color>처럼.","JPN":"例えば……毎年ある山荘に現れると言われている<color=#ffd34c>聖夜の殺人鬼</color>のように。","ENG":"The <color=#ffd34c>Killer of the Holy Night</color>, for example, is believed to appear at a certain mountain cabin every year.","TWN":"比如就像……某個山莊每年都會出現的<color=#ffd34c>耶誕的嫌疑犯</color>。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"......꿀꺽.","JPN":"……(ごくり)","ENG":"*Gulp*","TWN":"……咕嚕。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"산장이라...... 그게 설마 이 산장은 아니겠죠?","JPN":"山荘ですか……まさかこの山荘のことではありませんよね？","ENG":"A mountain cabin... It can't be this one, can it?","TWN":"山莊……不會就是這個山莊吧？"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"왜 아니겠나?","JPN":"そのまさかだが？","ENG":"Why not?","TWN":"懷疑嗎？"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"이 산장이 성야의 살인마가 출몰한다는 바로 그 공포의 산장일세.","JPN":"ここが聖夜の殺人鬼が現れるという、その恐怖の山荘だ。","ENG":"As a matter of fact, it is the very cabin rumored to be haunted by the Killer of the Holy Night.","TWN":"這個山莊就是耶誕的嫌疑犯出沒的那個可怕的山莊。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"하, 하지만 여기 있는 사람들은 모두 한가락 하는 카운터들이잖아?","JPN":"で、でもここにいるのはみんな、腕の立つカウンターたちでしょ？","ENG":"B-but everyone here is a Counter worth their salt.","TWN":"可、可是聚在這裡的人，不都是有能力的制裁者嗎？"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L16_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"살인마 따위가 덤벼들어 봤자 3초 컷이지.","JPN":"殺人鬼なんかがやって来たところで、3秒で終わりよ。","ENG":"Even the Killer wouldn't last three seconds against us.","TWN":"即使有殺人魔，估計三秒內就會被幹掉吧。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"안 그래, 버터맨?","JPN":"バターマンもそう思うでしょ？","ENG":"Don't you agree, Sleazeball?","TWN":"你說呢，油膩男？"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"걱정 말라고, 실비아.","JPN":"心配するな、シルビア。","ENG":"Don't worry, Sylvia.","TWN":"不用擔心，希爾維亞。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"무슨 유령 같은 게 아닌 이상, 이 비공인 탑 카운터 님이 한 방에 쓰러트려 줄 테니까.","JPN":"幽霊みたいなものでなければ、この非公認トップカウンター様が一発で仕留めてやるさ。","ENG":"Unless this Killer is some sort of ghost, I, the unofficial top Counter, could get rid of him with a single blow.","TWN":"只要不是鬼，我這個非公認制裁者就能一拳把他打趴下。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"후후. 그런 단순한 범죄자라면 <color=#ffd34c>성야의 살인마</color>라는 이명이 붙지도 않았겠지.","JPN":"そんな単純な犯罪者なら<color=#ffd34c>聖夜の殺人鬼</color>という異名がつくこともなかっただろう。","ENG":"Hah hah. If he was so easy to get rid of, he wouldn't have been called the <color=#ffd34c>Killer of the Holy Night</color>, now would he?","TWN":"哼，如果這麼容易就能打敗，就不會有<color=#ffd34c>耶誕的嫌疑犯</color>這個綽號了。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"살을 에는 북풍의 눈보라가 몰아치는 어두운 밤,","JPN":"肌を切るような北風の吹雪が吹き荒れる暗い夜。","ENG":"Legend says, during the dark, stormy winter night,","TWN":"在刺骨的暴風雪肆虐的黑夜，"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"살인마는 산장의 그림자 속에서 소리 없이 나타난다네.","JPN":"殺人鬼は山荘の影の中から音もなく現れるそうだ。","ENG":"the Killer would silently emerge out of the shadow of the cabin,","TWN":"殺人魔會悄無聲息地來到山莊。"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};